  1	import React, { FC, useState } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
  5	import { useIsWindowsBootableVolume } from '@catalog/CreateFromInstanceTypes/utils/utils';
  6	import { ConfigMapModel } from '@kubevirt-ui/kubevirt-api/console';
  7	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  8	import { IoK8sApiCoreV1ConfigMap } from '@kubevirt-ui/kubevirt-api/kubernetes';
  9	import ErrorAlert from '@kubevirt-utils/components/ErrorAlert/ErrorAlert';
 10	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 11	import { SecretSelectionOption } from '@kubevirt-utils/components/SSHSecretModal/utils/types';
 12	import { createSSHSecret } from '@kubevirt-utils/components/SSHSecretModal/utils/utils';
 13	import {
 14	  AUTOUNATTEND,
 15	  generateNewSysprepConfig,
 16	  UNATTEND,
 17	} from '@kubevirt-utils/components/SysprepModal/sysprep-utils';
 18	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
 19	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 20	import { logITFlowEvent } from '@kubevirt-utils/extensions/telemetry/telemetry';
 21	import {
 22	  CREATE_VM_BUTTON_CLICKED,
 23	  CREATE_VM_FAILED,
 24	  CREATE_VM_SUCCEEDED,
 25	  CUSTOMIZE_VM_BUTTON_CLICKED,
 26	  VIEW_YAML_AND_CLI_CLICKED,
 27	} from '@kubevirt-utils/extensions/telemetry/utils/constants';
 28	import { ALL_NAMESPACES_SESSION_KEY } from '@kubevirt-utils/hooks/constants';
 29	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 30	import useKubevirtUserSettings from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettings';
 31	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
 32	import useNamespaceUDN from '@kubevirt-utils/resources/udn/hooks/useNamespaceUDN';
 33	import { useDriversImage } from '@kubevirt-utils/resources/vm/utils/disk/useDriversImage';
 34	import { vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 35	import { createHeadlessService } from '@kubevirt-utils/utils/headless-service';
 36	import { isEmpty } from '@kubevirt-utils/utils/utils';
 37	import { k8sCreate } from '@openshift-console/dynamic-plugin-sdk';
 38	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 39	import { Checkbox, Stack, StackItem } from '@patternfly/react-core';
 40	
 41	import ActionButtons from './components/ActionButtons/ActionButtons';
 42	import YamlAndCLIViewerModal from './components/YamlAndCLIViewerModal/YamlAndCLIViewerModal';
 43	import useGeneratedVM from './hooks/useGeneratedVM';
 44	
 45	import './CreateVMFooter.scss';
 46	
 47	const CreateVMFooter: FC = () => {
 48	  const { t } = useKubevirtTranslation();
 49	  const navigate = useNavigate();
 50	  const [isSubmitting, setIsSubmitting] = useState(false);
 51	  const [error, setError] = useState<any | Error>(null);
 52	  const { createModal } = useModal();
 53	  const [_, driversImageLoading] = useDriversImage();
 54	
 55	  const [authorizedSSHKeys, setAuthorizedSSHKeys] = useKubevirtUserSettings('ssh');
 56	
 57	  const [activeNamespace] = useActiveNamespace();
 58	  const [isUDNManagedNamespace] = useNamespaceUDN(
 59	    activeNamespace === ALL_NAMESPACES_SESSION_KEY ? DEFAULT_NAMESPACE : activeNamespace,
 60	  );
 61	
 62	  const { instanceTypeVMState, setStartVM, setVM, startVM, vmNamespaceTarget } =
 63	    useInstanceTypeVMStore();
 64	  const { sshSecretCredentials, sysprepConfigMapData, vmName } = instanceTypeVMState;
 65	  const { applyKeyToProject, secretOption, sshPubKey, sshSecretName } = sshSecretCredentials || {};
 66	  const isWindowsOSVolume = useIsWindowsBootableVolume();
 67	
 68	  const generatedVM = useGeneratedVM();
 69	
 70	  const handleSubmit = async () => {
 71	    setIsSubmitting(true);
 72	    setError(null);
 73	
 74	    logITFlowEvent(CREATE_VM_BUTTON_CLICKED, generatedVM);
 75	
 76	    if (
 77	      applyKeyToProject &&
 78	      !isEmpty(sshSecretName) &&
 79	      authorizedSSHKeys?.[vmNamespaceTarget] !== sshSecretName
 80	    ) {
 81	      setAuthorizedSSHKeys({ ...authorizedSSHKeys, [vmNamespaceTarget]: sshSecretName });
 82	    }
 83	
 84	    return k8sCreate({
 85	      data: generatedVM,
 86	      model: VirtualMachineModel,
 87	    })
 88	      .then(async (createdVM) => {
 89	        if (secretOption === SecretSelectionOption.addNew) {
 90	          createSSHSecret(sshPubKey, sshSecretName, vmNamespaceTarget);
 91	        }
 92	
 93	        if (isWindowsOSVolume) {
 94	          const { data, name, shouldCreateNewConfigMap } = sysprepConfigMapData;
 95	          const { autounattend, unattended } = data;
 96	
 97	          if (shouldCreateNewConfigMap) {
 98	            const configMap = generateNewSysprepConfig({
 99	              data: { [AUTOUNATTEND]: autounattend, [UNATTEND]: unattended },
100	              sysprepName: name,
101	            });
102	
103	            await k8sCreate<IoK8sApiCoreV1ConfigMap>({
104	              data: configMap,
105	              model: ConfigMapModel,
106	              ns: vmNamespaceTarget,
107	            });
108	          }
109	        }
110	
111	        if (!isUDNManagedNamespace) createHeadlessService(createdVM);
112	
113	        navigate(getResourceUrl({ model: VirtualMachineModel, resource: createdVM }));
114	
115	        logITFlowEvent(CREATE_VM_SUCCEEDED, createdVM);
116	      })
117	      .catch((err) => {
118	        setError(err);
119	        logITFlowEvent(CREATE_VM_FAILED, null, { vmName: vmName });
120	      })
121	      .finally(() => setIsSubmitting(false));
122	  };
123	
124	  const handleCustomize = async () => {
125	    setIsSubmitting(true);
126	    setError(null);
127	
128	    try {
129	      await setVM(generatedVM);
130	      vmSignal.value = generatedVM;
131	
132	      logITFlowEvent(CUSTOMIZE_VM_BUTTON_CLICKED, vmSignal.value);
133	
134	      navigate(
135	        `/k8s/ns/${vmNamespaceTarget}/catalog/review/${VirtualMachineDetailsTab.Configurations}`,
136	      );
137	    } catch (err) {
138	      setError(err);
139	    } finally {
140	      setIsSubmitting(false);
141	    }
142	  };
143	
144	  return (
145	    <footer className="create-vm-instance-type-footer">
146	      <Stack hasGutter>
147	        {error && (
148	          <StackItem>
149	            <ErrorAlert error={error} />
150	          </StackItem>
151	        )}
152	        <StackItem>
153	          <Checkbox
154	            id="start-after-creation-checkbox"
155	            isChecked={startVM}
156	            label={t('Start this VirtualMachine after creation')}
157	            onChange={(_event, val) => setStartVM(val)}
158	          />
159	        </StackItem>
160	        <StackItem>
161	          <ActionButtons
162	            onViewYAML={() => {
163	              logITFlowEvent(VIEW_YAML_AND_CLI_CLICKED, null, { vmName: vmName });
164	              createModal((props) => <YamlAndCLIViewerModal vm={generatedVM} {...props} />);
165	            }}
166	            isLoading={isSubmitting || driversImageLoading}
167	            onCreate={handleSubmit}
168	            onCustomize={handleCustomize}
169	          />
170	        </StackItem>
171	      </Stack>
172	    </footer>
173	  );
174	};
175	
176	export default CreateVMFooter;

